```javascript
function solve(code, businessLine, isActive) {
    const validBusinessLines = new Set(["electronics", "grocery", "pharmacy", "restaurant"]);
    const businessPriority = {
        "electronics": 0,
        "grocery": 1,
        "pharmacy": 2,
        "restaurant": 3
    };

    const validCoupons = [];

    for (let i = 0; i < code.length; i++) {
        const c = code[i];
        const bl = businessLine[i];
        const a = isActive[i];

        if (c === "" || !/^[a-zA-Z0-9_]+$/.test(c)) continue;
        if (!validBusinessLines.has(bl)) continue;
        if (!a) continue;

        validCoupons.push({ code: c, business: bl });
    }

    validCoupons.sort((a, b) => {
        const pA = businessPriority[a.business];
        const pB = businessPriority[b.business];
        if (pA !== pB) return pA - pB;
        return a.code.localeCompare(b.code);
    });

    return validCoupons.map(c => c.code);
}
```

